import 'package:soilreport/src/localization/localization_extension.dart';
import 'package:soilreport/src/localization/string_hardcoded.dart';

/// Base class for all all client-side errors that can be generated by the app

enum AlertWidgetType {
  dialog,
  snack
}

sealed class AppException implements Exception {
  AppException(this.code, this.message, this.type);
  final String code;
  final String message;
  final StackTrace stackTrace = StackTrace.current;
  final AlertWidgetType type;

  @override
  String toString() => message;
}

/// Auth

class PasswordNotMatchException extends AppException {

  PasswordNotMatchException()
      : super('password-not-match', 'Passwords don\'t match'.hardcoded, AlertWidgetType.snack);
}

class PasswordInvalidException extends AppException {

  PasswordInvalidException()
      : super('password-invalid', 'Password is not valid'.hardcoded, AlertWidgetType.snack);
}

class CouldntSetPasswordException extends AppException {

  CouldntSetPasswordException()
      : super('couldnt-set-password', 'Couldn\'t set password'.hardcoded, AlertWidgetType.snack);
}

class WrongPhoneNumberException extends AppException {
  WrongPhoneNumberException()
      : super('wrong-phone-number', 'wrong phone number'.hardcoded, AlertWidgetType.snack);
}
class WrongOtpException extends AppException {
  WrongOtpException()
      : super('wrong-otp', 'wrong otp'.hardcoded, AlertWidgetType.dialog);
}

class ClientStatsFetchFailedException extends AppException {
