}

class NetworkIssueException extends AppException {
  NetworkIssueException() : super('network-issue', 'Network issue'.hardcoded, AlertWidgetType.snack);
}
class SystemErrorException extends AppException {
  final String? sysMessage;
  SystemErrorException({this.sysMessage}) : super("system-error-exception", sysMessage ?? 'system error'.hardcoded, AlertWidgetType.dialog);
}

class BiometricAuthenticationFailedException extends AppException {
